/* ================================================================
   ToyForge Studio — main.min.js  (mobile-fixed + animated videos)
   ================================================================ */

/* ── Smooth scroll ── */
let lenis;
if (window.Lenis) {
  lenis = new Lenis({ lerp: 0.085, smoothWheel: true });
  function raf(t) { lenis.raf(t); requestAnimationFrame(raf); }
  requestAnimationFrame(raf);
}

/* ── Cursor glow desktop only ── */
const cg = document.getElementById('cursor-glow');
if (window.matchMedia('(hover:hover)').matches && cg) {
  document.addEventListener('mousemove', e => {
    cg.style.left = e.clientX + 'px';
    cg.style.top  = e.clientY + 'px';
  });
}

/* ── Nav scroll ── */
const mainNav = document.getElementById('mainNav');
window.addEventListener('scroll', () =>
  mainNav && mainNav.classList.toggle('scrolled', window.scrollY > 60));

/* ── Hamburger ── */
const hamburger = document.getElementById('hamburger');
const mobileMenu = document.getElementById('mobileMenu');
if (hamburger && mobileMenu) {
  hamburger.addEventListener('click', () => mobileMenu.classList.toggle('open'));
  mobileMenu.querySelectorAll('a').forEach(a =>
    a.addEventListener('click', () => mobileMenu.classList.remove('open')));
}

/* ── Marquee ── */
const marqItems = ['FSC-Certified Wood','6 Shape Families','Montessori Aligned','EN71 Certified',
  'STEM-Focused','Award-Winning Design','Non-Toxic Paints','28 Countries','140K Families',
  'Carbon Neutral 2023','Lifetime Guarantee','Safety First'];
const track = document.getElementById('marqueeTrack');
if (track) {
  [...marqItems, ...marqItems].forEach(txt => {
    const d = document.createElement('div');
    d.className = 'marquee-item';
    d.innerHTML = `<span class="marquee-dot"></span>${txt}`;
    track.appendChild(d);
  });
}

/* ── Reveal on scroll ── */
const revObs = new IntersectionObserver(entries =>
  entries.forEach(e => { if (e.isIntersecting) e.target.classList.add('in'); }),
  { threshold: 0.1, rootMargin: '0px 0px -40px 0px' });
document.querySelectorAll('.reveal,.reveal-l,.reveal-r').forEach(el => revObs.observe(el));

/* ================================================================
   GSAP
   ================================================================ */
function initGSAP() {
  if (!window.gsap || !window.ScrollTrigger) return;
  gsap.registerPlugin(ScrollTrigger);
  gsap.from('.hero-eyebrow',       { opacity:0, y:30, duration:1,   ease:'power3.out', delay:.3 });
  gsap.from('.hero-title .line1',  { opacity:0, y:40, duration:1,   ease:'power3.out', delay:.5 });
  gsap.from('.hero-title .line2',  { opacity:0, y:40, duration:1,   ease:'power3.out', delay:.7 });
  gsap.from('.hero-sub',           { opacity:0, y:30, duration:1,   ease:'power3.out', delay:.85 });
  gsap.from('.hero-btns',          { opacity:0, y:20, duration:1,   ease:'power3.out', delay:1 });
  gsap.from('.scroll-cue',         { opacity:0,       duration:1,                      delay:1.4 });
  document.querySelectorAll('.stat-n').forEach(el => {
    const raw = el.textContent, suffix = raw.replace(/[0-9.]/g,''), val = parseFloat(raw);
    if (!isNaN(val)) ScrollTrigger.create({ trigger:el, start:'top 80%',
      onEnter:()=>gsap.fromTo({v:0},{v:val},{duration:1.8,ease:'power2.out',
        onUpdate(){ el.textContent=Math.round(this.targets()[0].v).toLocaleString()+suffix; }})});
  });
  gsap.from('.feat-card',{y:50,opacity:0,stagger:.12,duration:.9,ease:'power2.out',
    scrollTrigger:{trigger:'.feat-grid',start:'top 75%'}});
}

/* ================================================================
   THREE.JS helpers
   ================================================================ */
function waitForThree(cb) {
  if (window.THREE) { cb(); return; }
  const t = setInterval(() => { if (window.THREE) { clearInterval(t); cb(); } }, 50);
}

function lerp(a,b,t){ return a+(b-a)*t; }
function easeOut(t){ return 1-Math.pow(1-t,3); }

/* Unified drag — mouse + touch */
function makeDraggable(canvas, onDelta) {
  let down=false, px=0, py=0;
  const start=(x,y)=>{ down=true; px=x; py=y; };
  const move =(x,y)=>{ if(!down)return; onDelta(.009*(x-px),.009*(y-py)); px=x; py=y; };
  const end  =()=>{ down=false; };
  canvas.addEventListener('mousedown', e=>start(e.clientX,e.clientY));
  canvas.addEventListener('touchstart',e=>{ start(e.touches[0].clientX,e.touches[0].clientY); e.preventDefault(); },{passive:false});
  window.addEventListener('mousemove', e=>move(e.clientX,e.clientY));
  window.addEventListener('touchmove', e=>{ if(down)move(e.touches[0].clientX,e.touches[0].clientY); },{passive:true});
  window.addEventListener('mouseup',   end);
  window.addEventListener('touchend',  end);
}

/* Pause RAF when off-screen */
function pauseWhenHidden(canvas, loopFn) {
  let raf=null;
  function start(){ if(raf===null) loop(); }
  function stop(){ if(raf!==null){ cancelAnimationFrame(raf); raf=null; } }
  function loop(){ raf=requestAnimationFrame(()=>{ loopFn(); loop(); }); }
  const obs=new IntersectionObserver(entries=>
    entries.forEach(e=>e.isIntersecting?start():stop()),{threshold:0});
  obs.observe(canvas);
  start();
}

/* ================================================================
   HERO CANVAS — floating toy-fragment particles
   ================================================================ */
function initHeroCanvas() {
  const el = document.getElementById('hero-canvas');
  if (!el || !window.THREE) return;
  let W=window.innerWidth, H=window.innerHeight;
  const R=new THREE.WebGLRenderer({canvas:el,antialias:true,alpha:true});
  R.setSize(W,H); R.setPixelRatio(Math.min(devicePixelRatio,1.5)); R.setClearColor(0,0);
  const S=new THREE.Scene(), C=new THREE.PerspectiveCamera(60,W/H,.1,200);
  C.position.z=22;
  const COLS=[0xFF5A2C,0xFFD025,0x00C49A,0x8B6FE8,0xF53FA5,0x2BB8FF];
  const GEOS=[new THREE.BoxGeometry(.5,.5,.5),new THREE.OctahedronGeometry(.42),
    new THREE.TetrahedronGeometry(.46),new THREE.CylinderGeometry(0,.4,.75,5),
    new THREE.TorusGeometry(.36,.1,8,24),new THREE.CylinderGeometry(.38,.38,.2,6)];
  const COUNT=W<600?12:24;
  const meshes=[];
  for(let i=0;i<COUNT;i++){
    const m=new THREE.Mesh(GEOS[i%GEOS.length],
      new THREE.MeshPhongMaterial({color:COLS[i%6],opacity:.18+.22*Math.random(),transparent:true,shininess:80}));
    m.position.set(48*(Math.random()-.5),28*(Math.random()-.5),12*(Math.random()-.5)-6);
    m.userData={rx:.022*(Math.random()-.5),ry:.018*(Math.random()-.5),
      oy:m.position.y,fs:.4+.6*Math.random(),fo:Math.random()*Math.PI*2};
    S.add(m); meshes.push(m);
  }
  S.add(new THREE.AmbientLight(0xffffff,.5));
  const pL=new THREE.PointLight(0xFF5A2C,4,50); pL.position.set(0,8,10); S.add(pL);
  S.add(Object.assign(new THREE.PointLight(0x8B6FE8,3,40),{position:new THREE.Vector3(-14,-6,6)}));
  S.add(Object.assign(new THREE.PointLight(0xFFD025,2.5,35),{position:new THREE.Vector3(14,6,4)}));
  let t=0;
  pauseWhenHidden(el,()=>{
    t+=.012;
    meshes.forEach(m=>{
      m.rotation.x+=m.userData.rx; m.rotation.y+=m.userData.ry;
      m.position.y=m.userData.oy+.7*Math.sin(t*m.userData.fs+m.userData.fo);
    });
    pL.position.x=10*Math.cos(.6*t); pL.position.y=7*Math.sin(.4*t);
    R.render(S,C);
  });
  window.addEventListener('resize',()=>{W=window.innerWidth;H=window.innerHeight;R.setSize(W,H);C.aspect=W/H;C.updateProjectionMatrix();});
}

/* ================================================================
   TOY CANVAS FACTORY — reusable setup
   ================================================================ */
function createToyRenderer(id) {
  const el=document.getElementById(id);
  if(!el||!window.THREE) return null;
  const par=el.parentElement;
  // Force explicit size on parent so canvas knows its dimensions
  const rect=par.getBoundingClientRect();
  let W=Math.max(rect.width,120), H=Math.max(rect.height||rect.width,120);
  const R=new THREE.WebGLRenderer({canvas:el,antialias:true,alpha:true,powerPreference:'high-performance'});
  R.setSize(W,H,false); // false = don't set CSS size (let CSS handle it)
  R.setPixelRatio(Math.min(devicePixelRatio,2));
  R.setClearColor(0,0);
  R.shadowMap.enabled=true;
  const S=new THREE.Scene();
  const C=new THREE.PerspectiveCamera(48,W/H,.1,100);
  const onResize=()=>{
    const r2=par.getBoundingClientRect();
    W=Math.max(r2.width,120); H=Math.max(r2.height||r2.width,120);
    R.setSize(W,H,false); C.aspect=W/H; C.updateProjectionMatrix();
  };
  window.addEventListener('resize',onResize);
  return {el,R,S,C,par};
}

/* ================================================================
   TOY 1 — Shape Sorter 3-D
   ================================================================ */
function initToy1() {
  const ctx=createToyRenderer('toy1-canvas');
  if(!ctx) return;
  const {el,R,S,C}=ctx;
  C.position.set(0,1.5,10);
  S.add(new THREE.AmbientLight(0xffffff,.7));
  const pL=new THREE.PointLight(0xffffff,5,40); pL.position.set(5,8,8); pL.castShadow=true; S.add(pL);
  S.add(Object.assign(new THREE.PointLight(0xFF5A2C,2.5,30),{position:new THREE.Vector3(-5,-3,5)}));
  S.add(Object.assign(new THREE.PointLight(0xFFD025,2,25),  {position:new THREE.Vector3(3,6,-4)}));
  const G=new THREE.Group(); S.add(G);
  // Base board
  const base=new THREE.Mesh(new THREE.BoxGeometry(4.8,.28,2.2),
    new THREE.MeshPhongMaterial({color:0xE8C87A,shininess:60}));
  base.position.y=-1.7; base.castShadow=true; G.add(base);
  G.add(Object.assign(new THREE.Mesh(new THREE.BoxGeometry(4.9,.08,2.3),
    new THREE.MeshPhongMaterial({color:0xD4A855,shininess:80})),{position:new THREE.Vector3(0,-1.57,0)}));
  // Pegs + stacking pieces
  const PEGS=[{x:-2.2,c:0xFF5A2C,s:6},{x:-1.1,c:0xFFD025,s:32},{x:0,c:0x00C49A,s:3},{x:1.1,c:0x2BB8FF,s:4},{x:2.2,c:0x8B6FE8,s:4,r:Math.PI/4}];
  PEGS.forEach(p=>{
    const peg=new THREE.Mesh(new THREE.CylinderGeometry(.1,.1,2.2,12),
      new THREE.MeshPhongMaterial({color:0xE8E0C0,shininess:90}));
    peg.position.set(p.x,-.1,0); G.add(peg);
    const disc=new THREE.Mesh(new THREE.CylinderGeometry(.65,.65,.15,p.s),
      new THREE.MeshPhongMaterial({color:p.c,shininess:80}));
    disc.position.set(p.x,-1.58,0); if(p.r)disc.rotation.y=p.r; disc.castShadow=true; G.add(disc);
    for(let n=0;n<3;n++){
      const rad=.58-.09*n;
      const geo=p.s===3?new THREE.CylinderGeometry(0,rad,.32,3)
               :p.s===4?new THREE.BoxGeometry(1.6*rad,.27,1.6*rad)
               :         new THREE.CylinderGeometry(rad,rad,.27,p.s);
      const col=new THREE.Color(p.c); col.offsetHSL(0,0,.06*n-.05);
      const piece=new THREE.Mesh(geo,new THREE.MeshPhongMaterial({color:col,shininess:100}));
      piece.position.set(p.x,.42*n-1.24,0); if(p.r)piece.rotation.y=p.r;
      piece.castShadow=true; G.add(piece);
    }
  });
  let rotX=.25,rotY=.4,velX=0,velY=0,t=0;
  makeDraggable(el,(dx,dy)=>{ velY+=dx; velX+=dy; });
  pauseWhenHidden(el,()=>{
    t+=.014;
    velX*=.92; velY*=.92; rotY+=velY; rotX+=velX;
    rotX=Math.max(-.5,Math.min(.7,rotX));
    G.rotation.x=rotX; G.rotation.y=rotY;
    G.position.y=.15*Math.sin(.5*t);
    pL.intensity=4.5+.5*Math.sin(.7*t);
    R.render(S,C);
  });
}

/* ================================================================
   TOY 2 — Color Slide bead puzzle
   ================================================================ */
function initToy2() {
  const ctx=createToyRenderer('toy2-canvas');
  if(!ctx) return;
  const {el,R,S,C}=ctx;
  C.position.set(0,1.2,11);
  S.add(new THREE.AmbientLight(0xffffff,.6));
  const pL=new THREE.PointLight(0xffffff,5.5,45); pL.position.set(5,8,8); pL.castShadow=true; S.add(pL);
  S.add(Object.assign(new THREE.PointLight(0x8B6FE8,3,30),{position:new THREE.Vector3(-6,-3,5)}));
  S.add(Object.assign(new THREE.PointLight(0xF53FA5,2,22),{position:new THREE.Vector3(4,6,-4)}));
  const G=new THREE.Group(); S.add(G);
  const fMat=new THREE.MeshPhongMaterial({color:0xFFD025,shininess:80});
  // Frame
  [[4,.22,.32,0,2,0],[4,.22,.32,0,-2,0],[.22,4.22,.32,-2,0,0],[.22,4.22,.32,2,0,0]].forEach(([w,h,d,x,y,z])=>{
    const m=new THREE.Mesh(new THREE.BoxGeometry(w,h,d),fMat); m.position.set(x,y,z); m.castShadow=true; G.add(m);
  });
  const RCOLS=[[0xFF5A2C,0xFF8235],[0x00C49A,0x33D9B2],[0x2BB8FF,0x66CDFF],[0x8B6FE8,0xA98CF8]];
  const beads=[];
  for(let r=0;r<4;r++){
    const rx=1.1*(r-1.5);
    G.add(Object.assign(new THREE.Mesh(new THREE.CylinderGeometry(.055,.055,3.6,10),
      new THREE.MeshPhongMaterial({color:0xD4A855,shininess:60})),{position:new THREE.Vector3(rx,0,0)}));
    for(let b=0;b<3;b++){
      const bead=new THREE.Mesh(new THREE.CylinderGeometry(.42,.42,.32,28),
        new THREE.MeshPhongMaterial({color:RCOLS[r][b%2],shininess:110}));
      const bY=.9*b-1.3; bead.position.set(rx,bY,0); bead.castShadow=true; G.add(bead);
      beads.push({mesh:bead,bY,phase:.8*r+.6*b,speed:.6+.35*Math.random(),amp:.28+.18*Math.random()});
    }
  }
  let rotX=.15,rotY=.3,velX=0,velY=0,t=0;
  makeDraggable(el,(dx,dy)=>{ velY+=dx; velX+=dy; });
  pauseWhenHidden(el,()=>{
    t+=.014;
    velX*=.92; velY*=.92; rotY+=velY; rotX+=velX;
    rotX=Math.max(-.5,Math.min(.65,rotX));
    G.rotation.x=rotX; G.rotation.y=rotY;
    G.position.y=.12*Math.sin(.5*t);
    beads.forEach(b=>{ b.mesh.position.y=b.bY+Math.sin(t*b.speed+b.phase)*b.amp; });
    pL.intensity=5+.6*Math.sin(.7*t);
    R.render(S,C);
  });
}

/* ================================================================
   SHOWCASE — scroll-driven 3-D assembly (dark scene)
   ================================================================ */
function initShowcase() {
  const sec=document.getElementById('showcase');
  const el=document.getElementById('showcase-canvas');
  if(!el||!sec||!window.THREE) return;
  let W=window.innerWidth, H=window.innerHeight;
  const R=new THREE.WebGLRenderer({canvas:el,antialias:true,alpha:false});
  R.setSize(W,H); R.setPixelRatio(Math.min(devicePixelRatio,1.5));
  R.setClearColor(0x0E0E1A,1); R.shadowMap.enabled=true;
  const S=new THREE.Scene(), C=new THREE.PerspectiveCamera(50,W/H,.1,100);
  C.position.set(0,1,14);
  S.add(new THREE.AmbientLight(0xffffff,.35));
  const pL1=new THREE.PointLight(0xffffff,6,50); pL1.position.set(6,10,10); pL1.castShadow=true; S.add(pL1);
  const pL2=new THREE.PointLight(0xFFD025,3.5,35); pL2.position.set(-8,-4,6); S.add(pL2);
  const pL3=new THREE.PointLight(0xFF5A2C,3,30); pL3.position.set(4,8,-6); S.add(pL3);
  // Rim light for drama
  S.add(Object.assign(new THREE.PointLight(0x8B6FE8,2,20),{position:new THREE.Vector3(-6,0,-8)}));
  const G=new THREE.Group(); S.add(G);
  const base=new THREE.Mesh(new THREE.BoxGeometry(6,.32,2.6),
    new THREE.MeshPhongMaterial({color:0xE8C87A,shininess:70,specular:new THREE.Color(.25,.2,.05)}));
  base.userData={aY:-2,sY:16}; base.position.y=16; base.castShadow=true; G.add(base);
  const bTop=new THREE.Mesh(new THREE.BoxGeometry(6.1,.1,2.7),
    new THREE.MeshPhongMaterial({color:0xD4A855,shininess:90}));
  bTop.userData={aY:-1.72,sY:16.3}; bTop.position.y=16.3; G.add(bTop);
  const PEGS=[{x:-2.5,c:0xFF5A2C,s:6},{x:-1.25,c:0xFFD025,s:32},{x:0,c:0x00C49A,s:3},{x:1.25,c:0x2BB8FF,s:4},{x:2.5,c:0x8B6FE8,s:4,r:Math.PI/4}];
  const parts=[];
  PEGS.forEach((p,i)=>{
    const peg=new THREE.Mesh(new THREE.CylinderGeometry(.1,.1,2.4,12),
      new THREE.MeshPhongMaterial({color:0xE8E0C0,shininess:90}));
    peg.position.set(p.x,-.5,0); peg.userData={aY:-.5,sY:10+.6*i,delay:.12*i}; G.add(peg); parts.push(peg);
    const disc=new THREE.Mesh(new THREE.CylinderGeometry(.68,.68,.16,p.s),
      new THREE.MeshPhongMaterial({color:p.c,shininess:80}));
    disc.position.set(p.x,-1.72,0); if(p.r)disc.rotation.y=p.r;
    disc.userData={aY:-1.72,sY:10+.6*i,delay:.12*i}; G.add(disc); parts.push(disc);
    for(let n=0;n<3;n++){
      const rad=.62-.1*n;
      const geo=p.s===3?new THREE.CylinderGeometry(0,rad,.3,3):p.s===4?new THREE.BoxGeometry(1.65*rad,.28,1.65*rad):new THREE.CylinderGeometry(rad,rad,.28,p.s);
      const col=new THREE.Color(p.c); col.offsetHSL(0,0,.07*n-.06);
      const piece=new THREE.Mesh(geo,new THREE.MeshPhongMaterial({color:col,shininess:100}));
      const bY=.43*n-1.3; piece.position.set(p.x,bY+16,0); if(p.r)piece.rotation.y=p.r;
      piece.userData={aY:bY,sY:bY+16,delay:.065*(3*i+n)}; G.add(piece); parts.push(piece);
    }
  });
  const STEPS=[
    {eye:'The Foundation',title:'Precision-Milled Board',    desc:'Each sorting board is CNC-milled from sustainably sourced hardwood to ±0.1mm tolerances.'},
    {eye:'The Pegs',      title:'Colour-Coded Posts',         desc:'Smooth steel pegs with rubber-tipped caps guide little fingers to the right slot every time.'},
    {eye:'The Shapes',    title:'Six Geometry Families',      desc:'Hexagon, circle, triangle, square, diamond, star — precision-turned and hand-painted in safe water-based colours.'},
    {eye:'Complete',      title:'Ready for Play',             desc:'The finished Sort Master: a symphony of colour, geometry, and tactile joy — ready for thousands of hours of discovery.'}
  ];
  const scEye=document.getElementById('sc-eye'),scTitle=document.getElementById('sc-title'),
        scDesc=document.getElementById('sc-desc'),dots=document.querySelectorAll('.pdot');
  let step=-1,t=0;
  pauseWhenHidden(el,()=>{
    t+=.013;
    const rect=sec.getBoundingClientRect();
    const totalH=sec.offsetHeight-window.innerHeight;
    const progress=totalH>0?Math.max(0,Math.min(1,-rect.top/totalH)):0;
    const ns=Math.min(3,Math.floor(4*progress));
    if(ns!==step&&STEPS[ns]){
      step=ns;
      if(scEye)scEye.textContent=STEPS[ns].eye;
      if(scTitle)scTitle.textContent=STEPS[ns].title;
      if(scDesc)scDesc.textContent=STEPS[ns].desc;
      dots.forEach((d,idx)=>d.classList.toggle('active',idx===ns));
    }
    const tBase=progress>.05?base.userData.aY:base.userData.sY;
    base.position.y=lerp(base.position.y,tBase,.07);
    bTop.position.y=lerp(bTop.position.y,tBase+.3,.07);
    parts.forEach(p=>{
      const d=p.userData.delay||0;
      const pt=Math.max(0,Math.min(1,(progress-.1-d)/.65));
      const ty=lerp(p.userData.sY,p.userData.aY,easeOut(pt));
      p.position.y=lerp(p.position.y,ty,.055);
      p.rotation.y+=.012;
    });
    G.rotation.x=.04*Math.sin(.1*t)-.06*progress;
    G.rotation.y=.08*Math.sin(.14*t);
    pL1.intensity=5.5+.7*Math.sin(.6*t);
    pL2.intensity=3.2+.5*Math.cos(.4*t);
    R.render(S,C);
  });
  window.addEventListener('resize',()=>{W=window.innerWidth;H=window.innerHeight;R.setSize(W,H);C.aspect=W/H;C.updateProjectionMatrix();});
}

/* ================================================================
   CTA CANVAS
   ================================================================ */
function initCta() {
  const el=document.getElementById('cta-canvas');
  if(!el||!window.THREE) return;
  const par=el.parentElement;
  let W=par.clientWidth, H=par.clientHeight||500;
  const R=new THREE.WebGLRenderer({canvas:el,antialias:true,alpha:true});
  R.setSize(W,H); R.setPixelRatio(Math.min(devicePixelRatio,1.5)); R.setClearColor(0,0);
  const S=new THREE.Scene(), C=new THREE.PerspectiveCamera(60,W/H,.1,100); C.position.z=14;
  const COLS=[0xFF5A2C,0xFFD025,0x00C49A,0x8B6FE8,0xF53FA5,0x2BB8FF];
  const GEOS=[new THREE.BoxGeometry(.45,.45,.45),new THREE.OctahedronGeometry(.38),
    new THREE.TetrahedronGeometry(.42),new THREE.CylinderGeometry(0,.38,.7,4),
    new THREE.CylinderGeometry(.35,.35,.18,6),new THREE.TorusGeometry(.32,.1,8,20)];
  const COUNT=W<600?10:18;
  const meshes=[];
  for(let i=0;i<COUNT;i++){
    const m=new THREE.Mesh(GEOS[i%GEOS.length],
      new THREE.MeshPhongMaterial({color:COLS[i%6],opacity:.22+.28*Math.random(),transparent:true,shininess:90}));
    m.position.set(28*(Math.random()-.5),18*(Math.random()-.5),10*(Math.random()-.5)-4);
    m.userData={ry:.026*(Math.random()-.5),rx:.018*(Math.random()-.5),
      oy:m.position.y,fs:.4+.5*Math.random(),fo:Math.random()*Math.PI*2};
    S.add(m); meshes.push(m);
  }
  S.add(new THREE.AmbientLight(0xffffff,.35));
  const pL=new THREE.PointLight(0xFF5A2C,3.5,36); pL.position.set(0,6,7); S.add(pL);
  S.add(Object.assign(new THREE.PointLight(0x8B6FE8,2.8,28),{position:new THREE.Vector3(-10,-5,4)}));
  let t=0;
  pauseWhenHidden(el,()=>{
    t+=.012;
    meshes.forEach(m=>{
      m.rotation.y+=m.userData.ry; m.rotation.x+=m.userData.rx;
      m.position.y=m.userData.oy+.6*Math.sin(t*m.userData.fs+m.userData.fo);
    });
    pL.position.x=8*Math.cos(.7*t); pL.position.y=6*Math.sin(.5*t);
    R.render(S,C);
  });
  window.addEventListener('resize',()=>{W=par.clientWidth;H=par.clientHeight||500;R.setSize(W,H);C.aspect=W/H;C.updateProjectionMatrix();});
}

/* ================================================================
   BOOT — wait for window load so deferred scripts are ready
   ================================================================ */
window.addEventListener('load', () => {
  waitForThree(() => {
    initHeroCanvas();
    initToy1();
    initToy2();
    setTimeout(initShowcase, 200);
    setTimeout(initCta,      400);
  });
  setTimeout(initGSAP, 100);
});

/* ================================================================
   PANEL BG CANVAS — animated particle backgrounds
   replacing videos, works everywhere including mobile
   ================================================================ */
function initPanelBg(id, palette, shapes) {
  const el = document.getElementById(id);
  if (!el) return;
  const par = el.parentElement;
  let W = par.clientWidth || window.innerWidth;
  let H = par.clientHeight || window.innerHeight;
  const dpr = Math.min(devicePixelRatio, 2);
  el.width  = W * dpr;
  el.height = H * dpr;
  const ctx2 = el.getContext('2d');
  ctx2.scale(dpr, dpr);

  const COUNT = Math.min(28, Math.floor(W / 28));
  const items = Array.from({length: COUNT}, (_, i) => ({
    x: Math.random() * W,
    y: Math.random() * H,
    r: 18 + Math.random() * 34,
    vx: (.3 + Math.random() * .5) * (Math.random() > .5 ? 1 : -1),
    vy: (.2 + Math.random() * .4) * (Math.random() > .5 ? 1 : -1),
    rot: Math.random() * Math.PI * 2,
    vr: .008 + Math.random() * .018,
    color: palette[i % palette.length],
    shape: shapes[i % shapes.length],
    alpha: .13 + Math.random() * .22,
    pulse: Math.random() * Math.PI * 2,
    pulseSpeed: .02 + Math.random() * .03
  }));

  function drawShape(ctx2, shape, r) {
    ctx2.beginPath();
    switch (shape) {
      case 'circle': ctx2.arc(0,0,r,0,Math.PI*2); break;
      case 'square': ctx2.rect(-r*.8,-r*.8,r*1.6,r*1.6); break;
      case 'tri':
        ctx2.moveTo(0,-r); ctx2.lineTo(r*.87,r*.5); ctx2.lineTo(-r*.87,r*.5); ctx2.closePath(); break;
      case 'hex':
        for(let k=0;k<6;k++){ctx2.lineTo(r*Math.cos(k*Math.PI/3-Math.PI/6),r*Math.sin(k*Math.PI/3-Math.PI/6));}
        ctx2.closePath(); break;
      case 'star':
        for(let k=0;k<10;k++){const a=k*Math.PI/5-Math.PI/2,ri=k%2===0?r:r*.45;ctx2.lineTo(ri*Math.cos(a),ri*Math.sin(a));}
        ctx2.closePath(); break;
      case 'ring':
        ctx2.arc(0,0,r,0,Math.PI*2);
        ctx2.arc(0,0,r*.55,0,Math.PI*2,true); break;
    }
  }

  let t = 0, raf = null;
  function tick() {
    raf = requestAnimationFrame(tick);
    t++;
    ctx2.clearRect(0, 0, W, H);

    items.forEach(it => {
      it.x += it.vx; it.y += it.vy; it.rot += it.vr;
      it.pulse += it.pulseSpeed;
      if (it.x < -80) it.x = W + 60;
      if (it.x > W + 80) it.x = -60;
      if (it.y < -80) it.y = H + 60;
      if (it.y > H + 80) it.y = -60;
      const alpha = it.alpha * (.8 + .2 * Math.sin(it.pulse));
      ctx2.save();
      ctx2.globalAlpha = alpha;
      ctx2.fillStyle = it.color;
      ctx2.strokeStyle = it.color;
      ctx2.lineWidth = 2.5;
      ctx2.translate(it.x, it.y);
      ctx2.rotate(it.rot);
      drawShape(ctx2, it.shape, it.r);
      if (it.shape === 'ring') { ctx2.stroke(); } else { ctx2.fill(); }
      ctx2.restore();
    });
  }

  const obs = new IntersectionObserver(entries => {
    entries.forEach(en => {
      if (en.isIntersecting) { if (!raf) tick(); }
      else { if (raf) { cancelAnimationFrame(raf); raf = null; } }
    });
  }, { threshold: 0 });
  obs.observe(el);
  tick();

  window.addEventListener('resize', () => {
    W = par.clientWidth || window.innerWidth;
    H = par.clientHeight || window.innerHeight;
    el.width = W * dpr; el.height = H * dpr;
    ctx2.scale(dpr, dpr);
  });
}

/* Kick off panel backgrounds immediately (no THREE dependency) */
document.addEventListener('DOMContentLoaded', () => {
  // Panel 1 — warm coral/yellow shapes (Sort Master)
  initPanelBg('bg1-canvas',
    ['#FF5A2C','#FFD025','#FF8235','#FFBC5A','#FF4010'],
    ['circle','square','tri','hex','ring','star','square','circle']
  );
  // Panel 2 — cool purple/blue shapes (Color Slide)
  initPanelBg('bg2-canvas',
    ['#8B6FE8','#2BB8FF','#F53FA5','#A98CF8','#00C49A'],
    ['hex','ring','star','circle','tri','square','ring','hex']
  );
});
